<template><view class="page"><view v-if="loading" class="empty">行程加载中</view><block v-else-if="itinerary"><view class="hero"><text class="title">{{ itinerary.name }}</text><text class="summary">{{ itinerary.start_date }} 至 {{ itinerary.end_date }} · {{ itinerary.day_count }} 天</text><text class="summary">全程约 {{ distanceText(itinerary.distance_meters) }} · 驾车 {{ itinerary.duration_minutes }} 分钟</text></view><scroll-view scroll-x class="day-tabs"><view class="tabs"><view v-for="day in itinerary.days" :key="day.id" class="tab" :class="{active:activeDayId===day.id}" @click="activeDayId=day.id">第 {{ day.day_no }} 天</view></view></scroll-view><view v-if="activeDay" class="day-card"><text class="day-date">{{ activeDay.plan_date }} · {{ activeDay.day_start_time }}-{{ activeDay.day_end_time }}</text><view v-if="!activeDay.stops.length" class="empty-day">当天暂无地点</view><view v-for="(stop,index) in activeDay.stops" :key="stop.id" class="stop"><view class="stop-index">{{ index+1 }}</view><view class="stop-main" @click="navigate(stop)"><text class="stop-time">{{ stop.start_time }}-{{ stop.end_time }}</text><text class="stop-name">{{ stop.name }}</text><text class="stop-location">{{ stop.location || '地点位置待完善' }}</text><text v-if="stop.time_slot_text" class="stop-note">推荐时段 {{ stop.time_slot_text }}</text><text v-if="stop.schedule_conflict" class="conflict">当前顺序与每日时间有冲突</text></view><view class="actions"><text @click="moveOrder(index,-1)">上移</text><text @click="moveOrder(index,1)">下移</text><text @click="moveDay(stop,-1)">前日</text><text @click="moveDay(stop,1)">后日</text></view></view></view><button class="delete-button" @click="remove">删除行程</button></block><view v-else class="empty">行程不存在</view></view></template>
<script setup>import{computed,ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{deleteTravelItinerary,getTravelItinerary,moveTravelItineraryStop,reorderTravelItinerary}from'../../api/travel';const id=ref(0),itinerary=ref(null),activeDayId=ref(0),loading=ref(true);const activeDay=computed(()=>itinerary.value?.days.find(day=>day.id===activeDayId.value)||itinerary.value?.days[0]||null);const distanceText=value=>Number(value)>=1000?`${(Number(value)/1000).toFixed(1)} km`:`${value||0} m`;const load=async()=>{loading.value=true;try{itinerary.value=(await getTravelItinerary(id.value)).data||null;if(itinerary.value&&!itinerary.value.days.some(day=>day.id===activeDayId.value))activeDayId.value=itinerary.value.days[0]?.id||0}catch(error){uni.showToast({title:error.msg||'读取失败',icon:'none'})}finally{loading.value=false}};const apply=payload=>{itinerary.value=payload;if(!itinerary.value.days.some(day=>day.id===activeDayId.value))activeDayId.value=itinerary.value.days[0]?.id||0};const moveOrder=async(index,offset)=>{const day=activeDay.value,target=index+offset;if(!day||target<0||target>=day.stops.length)return;const ids=day.stops.map(item=>item.id);[ids[index],ids[target]]=[ids[target],ids[index]];try{apply((await reorderTravelItinerary(id.value,{day_id:day.id,stop_ids:ids})).data)}catch(error){uni.showToast({title:error.msg||'调整失败',icon:'none'})}};const moveDay=async(stop,offset)=>{const target=activeDay.value.day_no+offset;if(target<1)return;try{apply((await moveTravelItineraryStop(id.value,{stop_id:stop.id,target_day_no:target})).data)}catch(error){uni.showToast({title:error.msg||'移动失败',icon:'none'})}};const navigate=stop=>uni.openLocation({latitude:Number(stop.latitude),longitude:Number(stop.longitude),name:stop.name,address:stop.location||'',scale:16});const remove=()=>uni.showModal({title:'删除行程',content:'删除后不可恢复，确认删除吗？',success:async result=>{if(!result.confirm)return;try{await deleteTravelItinerary(id.value);uni.navigateBack()}catch(error){uni.showToast({title:error.msg||'删除失败',icon:'none'})}}});onLoad(options=>{id.value=Number(options.id||0);load()})</script>
<style scoped>.page{min-height:100vh;padding:24rpx;background:#f5f7fa;box-sizing:border-box}.hero,.day-card{border-radius:8rpx;background:#fff}.hero{padding:26rpx}.title,.summary{display:block}.title{font-size:34rpx;font-weight:700;color:#1f2937}.summary{margin-top:10rpx;color:#66758a;font-size:23rpx}.day-tabs{margin:22rpx -24rpx 0;white-space:nowrap}.tabs{display:inline-flex;gap:14rpx;padding:0 24rpx}.tab{padding:16rpx 28rpx;border-radius:32rpx;background:#e9edf3;color:#66758a;font-size:24rpx}.tab.active{background:#1677ff;color:#fff}.day-card{margin-top:20rpx;padding:0 22rpx}.day-date{display:block;padding:22rpx 0;color:#0f8e69;font-size:24rpx;font-weight:600}.stop{display:flex;gap:16rpx;padding:22rpx 0;border-top:1rpx solid #edf0f5}.stop-index{display:flex;align-items:center;justify-content:center;flex:0 0 auto;width:40rpx;height:40rpx;border-radius:50%;background:#1677ff;color:#fff;font-size:22rpx}.stop-main{display:flex;flex:1;flex-direction:column;min-width:0}.stop-time{color:#1677ff;font-size:22rpx}.stop-name{margin-top:5rpx;overflow:hidden;color:#1f2937;font-size:27rpx;font-weight:600;text-overflow:ellipsis;white-space:nowrap}.stop-location,.stop-note,.conflict{margin-top:7rpx;color:#8894a5;font-size:21rpx}.stop-note{color:#0f8e69}.conflict{color:#e9692c}.actions{display:flex;flex:0 0 62rpx;flex-direction:column;gap:8rpx;color:#1677ff;font-size:20rpx;text-align:right}.empty,.empty-day{padding:100rpx 0;color:#94a3b8;text-align:center;font-size:25rpx}.empty-day{padding:50rpx 0}.delete-button{margin-top:30rpx;background:#fff;color:#e9692c;font-size:26rpx}.delete-button::after{border:0}</style>
